import{_ as d,o as e,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Налаштування сторінок","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/Page/page-settings.md","filePath":"uk-UA/Page/page-settings.md","lastUpdated":1781962217000}'),o={name:"uk-UA/Page/page-settings.md"};function n(i,t,l,s,c,g){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="налаштування-сторінок" tabindex="-1">Налаштування сторінок <a class="header-anchor" href="#налаштування-сторінок" aria-label="Permalink to &quot;Налаштування сторінок&quot;">​</a></h1><p>Page settings керують відображенням сайту, типовими параметрами сторінки завантаження, фоновими зображеннями та виглядом адмін-панелі.</p><h2 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опція</th><th>Призначення</th></tr></thead><tbody><tr><td>Site title</td><td>Заголовок, який показується у вкладці браузера.</td></tr><tr><td>Site icon</td><td>Маленька іконка у вкладці браузера.</td></tr><tr><td>ImgBed name</td><td>Назва, що показується на frontend pages.</td></tr><tr><td>ImgBed logo</td><td>Зображення логотипа на frontend pages.</td></tr><tr><td>Logo link</td><td>URL, який відкривається після натискання на логотип або avatar.</td></tr><tr><td>Background switch interval</td><td>Інтервал ротації кількох фонів у мілісекундах. <code>60000</code> означає 60 секунд.</td></tr><tr><td>Background opacity</td><td>Прозорість фонового зображення від <code>0</code> до <code>1</code>. Менші значення роблять фон світлішим.</td></tr><tr><td>Default URL prefix</td><td>Prefix для генерації посилань на зображення. Порожнє поле означає, що використовується поточний домен сайту.</td></tr></tbody></table><h2 id="client-settings" tabindex="-1">Client Settings <a class="header-anchor" href="#client-settings" aria-label="Permalink to &quot;Client Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опція</th><th>Призначення</th></tr></thead><tbody><tr><td>Announcement</td><td>Оголошення вгорі сторінки завантаження. Підтримується HTML.</td></tr><tr><td>Default upload channel</td><td>Upload channel, вибраний на сторінці завантаження типово. Також можна вибрати Smart Dispatch.</td></tr><tr><td>Default upload directory</td><td>Типова директорія завантаження, наприклад <code>/user/</code>. Порожньо або <code>/</code> означає root.</td></tr><tr><td>Default naming method</td><td>Типова стратегія генерації filename після upload. Дивіться нижче.</td></tr><tr><td>Convert to WebP by default</td><td>Перетворює зображення на WebP перед upload.</td></tr><tr><td>Enable compression by default</td><td>Стискає зображення локально в браузері перед upload.</td></tr><tr><td>Default compression threshold</td><td>Автоматично стискає, коли зображення перевищує цей розмір у MB.</td></tr><tr><td>Default target size</td><td>Цільовий розмір файлу після стискання, у MB.</td></tr><tr><td>Login page background</td><td>Фонове зображення сторінки входу користувача.</td></tr><tr><td>Upload page background</td><td>Фонове зображення сторінки завантаження.</td></tr><tr><td>Footer portal link</td><td>URL, який відкриває footer portal button.</td></tr><tr><td>Hide footer</td><td>Приховує frontend footer, коли ввімкнено.</td></tr></tbody></table><h2 id="admin-settings" tabindex="-1">Admin Settings <a class="header-anchor" href="#admin-settings" aria-label="Permalink to &quot;Admin Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опція</th><th>Призначення</th></tr></thead><tbody><tr><td>Admin login background</td><td>Фонове зображення сторінки входу адміністратора.</td></tr><tr><td>Admin background</td><td>Фонове зображення admin pages. Можна вказати один image URL або кілька URL.</td></tr><tr><td>Image loading mode</td><td>Режим завантаження preview для admin file list. Original завантажує оригінальні зображення. Smart loading надає перевагу thumbnails для публічних зображень і originals для restricted images.</td></tr><tr><td>Thumbnail source</td><td>Сервіс для генерації thumbnails: wsrv.nl, Cloudflare Image Resizing або WordPress Photon. Cloudflare Image Resizing потрібно ввімкнути в Cloudflare перед вибором.</td></tr><tr><td>Live2D widget</td><td>Показує Live2D-персонажа в адмін-панелі.</td></tr><tr><td>Firework click effect</td><td>Показує ефект феєрверка під час натискання на сторінку.</td></tr><tr><td>Star cursor trail</td><td>Показує зоряний слід під час руху миші.</td></tr></tbody></table><h2 id="формати-фонових-зображень" tabindex="-1">Формати фонових зображень <a class="header-anchor" href="#формати-фонових-зображень" aria-label="Permalink to &quot;Формати фонових зображень&quot;">​</a></h2><p>Login page background, upload page background і admin login background підтримують такі формати:</p><table tabindex="0"><thead><tr><th>Значення</th><th>Ефект</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Використовує ротацію шпалер Bing.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>Ротує кілька зображень.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>Використовує одне фонове зображення.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>Використовує random image API link. Можна налаштувати власний Random Image API в Other Settings, а потім вставити згенероване random image link як single-background entry.</td></tr></tbody></table><p>Admin background підтримує image URLs. Кілька URL можна розділяти англійськими комами, як підказано на сторінці. Порожнє поле означає default background.</p><h2 id="default-naming-method" tabindex="-1">Default Naming Method <a class="header-anchor" href="#default-naming-method" aria-label="Permalink to &quot;Default Naming Method&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Result</th></tr></thead><tbody><tr><td>Default</td><td>Time-random prefix + original filename, наприклад <code>1760000000000_cat.png</code>.</td></tr><tr><td>Prefix only</td><td>Тільки time-random prefix і extension, наприклад <code>1760000000000.png</code>.</td></tr><tr><td>Original name only</td><td>Зберігає original filename, наприклад <code>cat.png</code>. Якщо є дубль, ImgBed додає <code>(1)</code>, <code>(2)</code> і так далі.</td></tr><tr><td>Short link</td><td>Використовує 8-символьний short ID і extension, наприклад <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const u=d(o,[["render",n]]);export{m as __pageData,u as default};
